import{_ as e,o as t,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const k=JSON.parse('{"title":"配置","description":"","frontmatter":{},"headers":[],"relativePath":"zh/settings/index.md","filePath":"zh/settings/index.md","lastUpdated":1782688753000}'),r={name:"zh/settings/index.md"};function n(o,a,l,d,h,p){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h1><p>EasyYapi 提供了灵活的配置系统来自定义 API 文档生成行为。</p><h2 id="开箱即用" tabindex="-1">开箱即用 <a class="header-anchor" href="#开箱即用" aria-label="Permalink to &quot;开箱即用&quot;">​</a></h2><p>EasyApi 开箱即用地支持标准 HTTP 框架（Spring MVC、WebFlux、JAX-RS、Feign）—— <strong>大多数项目无需自定义规则</strong>。对于扫描器无法察觉的自定义框架行为（例如要求添加请求头的 <code>jakarta.servlet.Filter</code>，或将每个响应包装在信封中的 <code>ResponseBodyAdvice</code>），可使用内置的 AI 助手或外部 skill 来检测并生成规则。完整指南请参见 <a href="./rule-authoring">规则编写</a>。</p><h2 id="编写规则的方式" tabindex="-1">编写规则的方式 <a class="header-anchor" href="#编写规则的方式" aria-label="Permalink to &quot;编写规则的方式&quot;">​</a></h2><p>EasyYapi 3.x 提供 <strong>两种方式</strong> 来编写规则。两种方式都写入 <code>.easyapi/*.rules</code> 文件。完整指南请参见 <a href="./rule-authoring">规则编写</a>。</p><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th></tr></thead><tbody><tr><td><a href="./rule-authoring#内置-ai-助手">内置 AI 助手</a></td><td>在 Settings → Rules → Chat / Magic 中用自然语言编写规则</td></tr><tr><td><a href="./rule-authoring#外部-easy-yapi-assistant-skill">外部 <code>easy-yapi-assistant</code> skill</a></td><td>通过外部 AI 工具驱动规则编写</td></tr></tbody></table><h2 id="配置方式" tabindex="-1">配置方式 <a class="header-anchor" href="#配置方式" aria-label="Permalink to &quot;配置方式&quot;">​</a></h2><h3 id="本地配置文件" tabindex="-1">本地配置文件 <a class="header-anchor" href="#本地配置文件" aria-label="Permalink to &quot;本地配置文件&quot;">​</a></h3><p>在项目根目录（你在 IDE 中打开的文件夹）创建 <code>.easy.api.config</code> 文件（旧版，仍支持）。新项目应使用 <a href="./local-file-config"><code>.easyapi/</code> 文件夹模型</a>。规则文件仅基于工程根目录解析，不存在按模块划分的配置层。</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 忽略特定字段</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.hasAnn(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.fasterxml.jackson.annotation.JsonIgnore&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 类型转换</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;java.util.Date&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.lang.String</span></span></code></pre></div><p>详见 <a href="./local-file-config">本地配置文件</a>。</p><h3 id="远程配置文件" tabindex="-1">远程配置文件 <a class="header-anchor" href="#远程配置文件" aria-label="Permalink to &quot;远程配置文件&quot;">​</a></h3><p>配置远程 URL 来获取配置：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">remote.url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=http://your-config-server.com/easy-api.config</span></span></code></pre></div><p>详见 <a href="./remote-config">远程配置文件</a>。</p><h3 id="ide-设置" tabindex="-1">IDE 设置 <a class="header-anchor" href="#ide-设置" aria-label="Permalink to &quot;IDE 设置&quot;">​</a></h3><p>在 IDE 中配置 EasyYapi 的全局设置。</p><p>详见 <a href="./ide-setting">IDE 设置</a>。</p><h2 id="配置内容" tabindex="-1">配置内容 <a class="header-anchor" href="#配置内容" aria-label="Permalink to &quot;配置内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>说明</th></tr></thead><tbody><tr><td><a href="./rules/">配置规则</a></td><td>自定义 API 文档生成的规则</td></tr><tr><td><a href="./events/">事件回调</a></td><td>在特定事件发生时执行自定义逻辑</td></tr><tr><td><a href="./tools/">脚本工具</a></td><td>在 Groovy 脚本中可用的工具</td></tr><tr><td><a href="./advanced/">高级配置</a></td><td>高级自定义配置</td></tr></tbody></table><h2 id="配置优先级" tabindex="-1">配置优先级 <a class="header-anchor" href="#配置优先级" aria-label="Permalink to &quot;配置优先级&quot;">​</a></h2><ol><li>工程规则 —— <code>&lt;project&gt;/.easyapi/</code> + 从工程根目录向上查找的旧版 <code>.easy.api.config*</code>（最高优先级）</li><li>扩展规则 —— 内置框架预设（Spring、Jackson、Validation……）</li><li>远程配置 —— 来自 <code>remote.url</code> 的 URL</li><li>全局规则 —— <code>~/.easyapi/</code>（最低优先级）</li></ol>`,23)])])}const g=e(r,[["render",n]]);export{k as __pageData,g as default};
